    /**
     * Interceptor that enforces message size validation and basic rate limiting
     * at the gRPC layer to prevent DoS attacks.
     */
    public static class DoSProtectionInterceptor implements ServerInterceptor {

        private final AtomicLong activeRequests = new AtomicLong(0);
        private static final long MAX_ACTIVE_REQUESTS = 1000;

        @Override
        public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
                ServerCall<ReqT, RespT> call,
                Metadata headers,
                ServerCallHandler<ReqT, RespT> next) {

            // Check active request count to prevent resource exhaustion
            long current = activeRequests.incrementAndGet();
            if (current > MAX_ACTIVE_REQUESTS) {
                activeRequests.decrementAndGet();
                call.close(Status.RESOURCE_EXHAUSTED
                        .withDescription("Server is overloaded. Too many active requests: " + current),
                        new Metadata());
                return new ServerCall.Listener<ReqT>() {};
            }

            // Validate metadata size is reasonable
            String contentType = headers.get(Metadata.Key.of("content-type", Metadata.ASCII_STRING_MARSHALLER));

            ServerCall<ReqT, RespT> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
                @Override
                public void close(Status status, Metadata trailers) {
                    activeRequests.decrementAndGet();
                    super.close(status, trailers);
                }
            };

            ServerCall.Listener<ReqT> listener = next.startCall(wrappedCall, headers);

            return new ForwardingServerCallListener.SimpleForwardingServerCallListener<ReqT>(listener) {
                private long messageCount = 0;
                private static final long MAX_MESSAGES_PER_STREAM = 100_000;

                @Override
                public void onMessage(ReqT message) {
                    messageCount++;
                    if (messageCount > MAX_MESSAGES_PER_STREAM) {
                        wrappedCall.close(Status.RESOURCE_EXHAUSTED
                                        .withDescription("Too many messages in a single stream"),
                                new Metadata());
                        return;
                    }
                    super.onMessage(message);
                }

                @Override
                public void onHalfClose() {
                    try {
                        super.onHalfClose();
                    } catch (Exception e) {
                        logger.log(Level.WARNING, "Error processing request", e);
                        wrappedCall.close(Status.INTERNAL
                                        .withDescription("Internal processing error"),
                                new Metadata());
                    }
                }
            };
        }
    }

