    /**
     * Configures and starts the gRPC server with DoS protection settings.
     * Key protections:
     * - maxInboundMessageSize: Limits individual message sizes
     * - maxInboundMetadataSize: Limits header/metadata sizes
     * - maxConcurrentCallsPerConnection: Limits concurrent streams
     * - Connection age and idle timeout: Prevents connection hoarding
     */
    public static class FileServer {

        private Server server;
        private final int port;

        public FileServer(int port) {
            this.port = port;
        }

        public void start() throws IOException {
            server = NettyServerBuilder.forPort(port)
                    // --- DoS Protection: Message size limits ---
                    // This is the PRIMARY defense against large message DoS attacks.
                    // Even though clients may send "arbitrary" sizes via streaming,
                    // each individual message/chunk is bounded.
                    .maxInboundMessageSize(MAX_INBOUND_MESSAGE_SIZE)
                    .maxInboundMetadataSize(MAX_INBOUND_METADATA_SIZE)

                    // --- DoS Protection: Connection-level limits ---
                    .maxConcurrentCallsPerConnection(MAX_CONCURRENT_STREAMS)

                    // --- DoS Protection: Connection lifecycle management ---
                    // Force connections to refresh periodically, preventing
                    // long-lived connections from accumulating resources
                    .maxConnectionIdle(CONNECTION_IDLE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                    .maxConnectionAge(MAX_CONNECTION_AGE_SECONDS, TimeUnit.SECONDS)
                    .maxConnectionAgeGrace(60, TimeUnit.SECONDS)

                    // --- DoS Protection: Keepalive settings ---
                    // Detect and close dead connections
                    .keepAliveTime(60, TimeUnit.SECONDS)
                    .keepAliveTimeout(20, TimeUnit.SECONDS)
                    .permitKeepAliveTime(10, TimeUnit.SECONDS)
                    .permitKeepAliveWithoutCalls(false)

                    // --- DoS Protection: Flow control ---
                    // Limit the amount of data buffered per stream
                    .flowControlWindow(1 * 1024 * 1024) // 1 MB flow control window

                    // --- DoS Protection: Server interceptor ---
                    .intercept(new DoSProtectionInterceptor())

                    // --- Service registration ---
                    .addService(new FileServiceImpl())

                    .build()
                    .start();

            logger.info("FileService gRPC server started on port " + port);
            logger.info("Security settings:");
            logger.info("  Max inbound message size: " + MAX_INBOUND_MESSAGE_SIZE + " bytes");
            logger.info("  Max inbound metadata size: " + MAX_INBOUND_METADATA_SIZE + " bytes");
            logger.info("  Max chunk size (application): " + MAX_CHUNK_SIZE + " bytes");
            logger.info("  Max total file size: " + MAX_TOTAL_FILE_SIZE + " bytes");
            logger.info("  Max concurrent streams per connection: " + MAX_CONCURRENT_STREAMS);

            Runtime.getRuntime().addShutdownHook(new Thread(() -> {
                logger.info("Shutting down gRPC server...");
                try {
                    FileServer.this.stop();
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
                logger.info("Server shut down.");
            }));
        }

        public void stop() throws InterruptedException {
            if (server != null) {
                server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
            }
        }

        public void blockUntilShutdown() throws InterruptedException {
            if (server != null) {
                server.awaitTermination();
            }
        }
    }

