    /**
     * Client with matching size limits to prevent accidental oversized sends.
     */
    public static class FileServiceClient {

        private final ManagedChannel channel;
        private final FileServiceGrpc.FileServiceBlockingStub blockingStub;
        private final FileServiceGrpc.FileServiceStub asyncStub;

        public FileServiceClient(String host, int port) {
            channel = NettyChannelBuilder.forAddress(host, port)
                    .usePlaintext() // Use TLS in production!
                    // Client-side message size limits
                    .maxInboundMessageSize(MAX_INBOUND_MESSAGE_SIZE)
                    .maxInboundMetadataSize(MAX_INBOUND_METADATA_SIZE)
                    // Keepalive
                    .keepAliveTime(60, TimeUnit.SECONDS)
                    .keepAliveTimeout(20, TimeUnit.SECONDS)
                    .build();

            blockingStub = FileServiceGrpc.newBlockingStub(channel);
            asyncStub = FileServiceGrpc.newStub(channel)
                    .withDeadlineAfter(5, TimeUnit.MINUTES); // Request deadline
        }

        /**
         * Upload a file using client-streaming, sending data in safe chunk sizes.
         */
        public void uploadFile(String filePath) throws InterruptedException, IOException {
            Path path = Paths.get(filePath);
            if (!Files.exists(path)) {
                logger.warning("File not found: " + filePath);
                return;
            }

            long fileSize = Files.size(path);
            if (fileSize > MAX_TOTAL_FILE_SIZE) {
                logger.warning("File too large: " + fileSize + " bytes (max: " + MAX_TOTAL_FILE_SIZE + ")");
                return;
            }

            CountDownLatch latch = new CountDownLatch(1);

            StreamObserver<UploadStatus> responseObserver = new StreamObserver<UploadStatus>() {
                @Override
                public void onNext(UploadStatus status) {
                    logger.info("Upload status: " + status.getFilename()
                            + " success=" + status.getSuccess()
                            + " message=" + status.getMessage()
                            + " bytesReceived=" + status.getBytesReceived());
                }

                @Override
                public void onError(Throwable t) {
                    logger.log(Level.WARNING, "Upload failed", t);
                    latch.countDown();
                }

                @Override
                public void onCompleted() {
                    logger.info("Upload stream completed");
                    latch.countDown();
                }
            };

            // Set a deadline for the upload
            StreamObserver<FileChunk> requestObserver = asyncStub
                    .withDeadlineAfter(10, TimeUnit.MINUTES)
                    .uploadFile(responseObserver);

            try (InputStream inputStream = new BufferedInputStream(new FileInputStream(path.toFile()))) {
                byte[] buffer = new byte[MAX_CHUNK_SIZE];
                int bytesRead;
                long offset = 0;
                String filename = path.getFileName().toString();

                while ((bytesRead = inputStream.read(buffer)) != -1) {
                    FileChunk chunk = FileChunk.newBuilder()
                            .setFilename(filename)
                            .setData(com.google.protobuf.ByteString.copyFrom(buffer, 0, bytesRead))
                            .setOffset(offset)
                            .setTotalSize(fileSize)
                            .build();

                    requestObserver.onNext(chunk);
                    offset += bytesRead;

                    logger.info("Sent chunk: offset=" + (offset - bytesRead) + ", size=" + bytesRead);
                }
            } catch (RuntimeException e) {
                requestObserver.onError(e);
                throw e;
            }

            requestObserver.onCompleted();
            if (!latch.await(10, TimeUnit.MINUTES)) {
                logger.warning("Upload timed out");
            }
        }

        /**
         * Download a file using server-streaming.
         */
        public void downloadFile(String filename, String outputPath) throws IOException {
            DataRequest request = DataRequest.newBuilder()
                    .setQuery(filename)
                    .build();

            try (OutputStream outputStream = new BufferedOutputStream(
                    new FileOutputStream(outputPath))) {

                java.util.Iterator<FileChunk> chunks = blockingStub
                        .withDeadlineAfter(10, TimeUnit.MINUTES)
                        .downloadFile(request);

                long totalReceived = 0;
                while (chunks.hasNext()) {
                    FileChunk chunk = chunks.next();
                    byte[] data = chunk.getData().toByteArray();
                    outputStream.write(data);
                    totalReceived += data.length;

                    logger.info("Received chunk: offset=" + chunk.getOffset()
                            + ", size=" + data.length
                            + ", totalReceived=" + totalReceived);
                }

                logger.info("Download completed: " + filename + ", totalBytes=" + totalReceived);
            } catch (StatusRuntimeException e) {
                logger.log(Level.WARNING, "Download failed: " + e.getStatus(), e);
            }
        }

        /**
         * Bidirectional streaming for data processing.
         */
        public void processDataBidirectional(java.util.List<String> queries) throws InterruptedException {
            CountDownLatch latch = new CountDownLatch(1);

            StreamObserver<DataResponse> responseObserver = new StreamObserver<DataResponse>() {
                @Override
                public void onNext(DataResponse response) {
                    logger.info("Received response #" + response.getSequenceNumber()
                            + ": status=" + response.getStatus()
                            + ", payloadSize=" + response.getPayload().size());
                }

                @Override
                public void onError(Throwable t) {
                    logger.log(Level.WARNING, "Bidirectional stream error", t);
                    latch.countDown();
                }

                @Override
                public void onCompleted() {
                    logger.info("Bidirectional stream completed");
                    latch.countDown();
                }
            };

            StreamObserver<DataRequest> requestObserver = asyncStub
                    .withDeadlineAfter(5, TimeUnit.MINUTES)
                    .processData(responseObserver);

            try {
                for (String query : queries) {
                    DataRequest request = DataRequest.newBuilder()
                            .setQuery(query)
                            .putMetadata("timestamp", String.valueOf(System.currentTimeMillis()))
                            .putMetadata("client", "data-processor-v1")
                            .build();

                    requestObserver.onNext(request);
                    logger.info("Sent data request: " + query);

                    // Small delay to simulate real-world usage
                    Thread.sleep(100);
                }
            } catch (RuntimeException e) {
                requestObserver.onError(e);
                throw e;
            }

            requestObserver.onCompleted();
            if (!latch.await(5, TimeUnit.MINUTES)) {
                logger.warning("Bidirectional processing timed out");
            }
        }

        public void shutdown() throws InterruptedException {
            channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
        }
    }

    // ==================== Main Entry Point ====================

    public static void main(String[] args) throws Exception {
        if (args.length > 0 && "client".equals(args[0])) {
            // Run as client
            FileServiceClient client = new FileServiceClient("localhost", 9090);
            try {
                if (args.length > 2 && "upload".equals(args[1])) {
                    client.uploadFile(args[2]);
                } else if (args.length > 3 && "download".equals(args[1])) {
                    client.downloadFile(args[2], args[3]);
                } else if ("process".equals(args[1])) {
                    java.util.List<String> queries = java.util.Arrays.asList(
                            "SELECT * FROM data WHERE id > 100",
                            "AGGREGATE sum(value) GROUP BY category",
                            "TRANSFORM normalize(column_a, column_b)"
                    );
                    client.processDataBidirectional(queries);
                } else {
                    System.out.println("Usage:");
                    System.out.println("  client upload <filepath>");
                    System.out.println("  client download <filename> <outputpath>");
                    System.out.println("  client process");
                }
            } finally {
                client.shutdown();
            }
        } else {
            // Run as server
            FileServer server = new FileServer(9090);
            server.start();
            server.blockUntilShutdown();
        }
    }
